import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));
        long maxTime = 0;
        for (long[] e : edges) {
            maxTime = Math.max(maxTime, e[2]);
        }
        long low = 0;
        long high = maxTime;
        long answer = high;
        while (low <= high) {
            long mid = (low + high) / 2;
            if (check(n, edges, mid, k)) {
                answer = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return answer;
    }

    private static boolean check(long n, long[][] edges, long t, long k) {
        List<List<Long>> adj = new ArrayList<>();
        for (long i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }
        for (long[] e : edges) {
            if (e[2] > t) {
                adj.get((int) e[0]).add(e[1]);
                adj.get((int) e[1]).add(e[0]);
            }
        }
        boolean[] visited = new boolean[(int) n];
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (!visited[i]) {
                count++;
                dfs(i, adj, visited);
            }
        }
        return count >= k;
    }

    private static void dfs(int node, List<List<Long>> adj, boolean[] visited) {
        visited[node] = true;
        for (long neighbor : adj.get(node)) {
            if (!visited[(int) neighbor]) {
                dfs((int) neighbor, adj, visited);
            }
        }
    }
}
