public static long solve(long n, long[][] edges, long k) {
    class DSU {
        private int[] parent;
        private int[] rank;

        public DSU(int size) {
            parent = new int[size];
            rank = new int[size];
            for (int i = 0; i < size; i++) {
                parent[i] = i;
                rank[i] = 1;
            }
        }

        public int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        public void union(int x, int y) {
            int xroot = find(x);
            int yroot = find(y);
            if (xroot == yroot) return;
            if (rank[xroot] < rank[yroot]) {
                parent[xroot] = yroot;
            } else {
                parent[yroot] = xroot;
                if (rank[xroot] == rank[yroot]) {
                    rank[xroot]++;
                }
            }
        }

        public int getComponentCount() {
            Set<Integer> roots = new HashSet<>();
            for (int i = 0; i < parent.length; i++) {
                roots.add(find(i));
            }
            return roots.size();
        }
    }

    if (k == n) {
        return 0;
    }

    long maxTime = 0;
    for (long[] edge : edges) {
        if (edge[2] > maxTime) {
            maxTime = edge[2];
        }
    }

    long low = 0;
    long high = maxTime;
    long answer = maxTime;

    while (low <= high) {
        long mid = (low + high) / 2;
        DSU dsu = new DSU((int) n);
        for (long[] edge : edges) {
            if (edge[2] > mid) {
                dsu.union((int) edge[0], (int) edge[1]);
            }
        }
        int components = dsu.getComponentCount();
        if (components >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
